import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def calculate_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    if not unvisited_customers:
        return None

    min_distance = float('inf')
    best_node = None

    for i, customer in enumerate(unvisited_customers):
        distance = calculate_distance(cur_truck_pos, customer)
        future_impact = 0

        for other_truck_pos in all_truck_pos:
            future_impact += calculate_distance(other_truck_pos, customer)

        if distance + future_impact < min_distance:
            min_distance = distance + future_impact
            best_node = i

    return best_node
